//import { useState } from "react";
import "./style.css";
/*

            <button
                className="profile-btn"
                onClick={() => setShowProfile(true)}
            >
                ☰ Profile
            </button>
*/ 
function Profile({closeProfile}) {

    //const [showProfile, setShowProfile=true] = useState(true);

    return (
        <div>
            {/* Profile Sidebar */}
            <div className={`profile-sidebar "active"`}>

                <button
                    className="close-btn"
                    onClick={closeProfile}
                >
                    ✖
                </button>

                <h2>My Profile</h2>

                <div className="profile-image">
                    👤
                </div>

                <div className="info">
                    <p><strong>Name:</strong> Likhitha Sai</p>
                    <p><strong>Age:</strong> 20</p>
                    <p><strong>Gender:</strong> Female</p>
                    <p><strong>Height:</strong> 165 cm</p>
                    <p><strong>Weight:</strong> 55 kg</p>
                    <p><strong>Username:</strong> likhitha123</p>
                </div>

                <button className="profile-option">
                    Edit Profile
                </button>

                <button className="profile-option">
                    Exercise History
                </button>

                <button className="profile-option logout">
                    Logout
                </button>

            </div>

        </div>
    );
}

export default Profile;
